param(
    [string]$RepoRoot = (Get-Location).Path
)

$ErrorActionPreference = "Stop"

function Write-Info([string]$Message) {
    Write-Host "[JARVIS Patch 008] $Message"
}

$requiredFiles = @(
    "backend\src\services\agent-state.ts",
    "backend\src\routes\dashboard.routes.ts",
    "desktop-agent\src\main.py",
    "desktop-agent\src\local_api.py",
    "desktop-agent\config.json"
)

foreach ($relative in $requiredFiles) {
    $path = Join-Path $RepoRoot $relative
    if (-not (Test-Path $path)) {
        throw "File not found: $path"
    }
}

$timestamp = Get-Date -Format "yyyyMMdd-HHmmss"
$backupRoot = Join-Path $RepoRoot ".jarvis-patch-backups\patch-008-health-runtime-$timestamp"
New-Item -ItemType Directory -Path $backupRoot -Force | Out-Null

$pathsToBackup = @(
    "backend\src\services\agent-state.ts",
    "backend\src\routes\dashboard.routes.ts",
    "desktop-agent\src\main.py",
    "desktop-agent\src\local_api.py",
    "desktop-agent\config.json",
    "docs\HEALTH_RUNTIME.md"
)

foreach ($relative in $pathsToBackup) {
    $source = Join-Path $RepoRoot $relative
    if (Test-Path $source) {
        $target = Join-Path $backupRoot $relative
        New-Item -ItemType Directory -Path (Split-Path $target -Parent) -Force | Out-Null
        Copy-Item -LiteralPath $source -Destination $target -Force
    }
}

Write-Info "Backups created: $backupRoot"

$encoded = ""
$bytes = [System.Convert]::FromBase64String($encoded)
$tempPatch = Join-Path $env:TEMP ("jarvis_patch_008_" + [guid]::NewGuid().ToString("N") + ".py")
[System.IO.File]::WriteAllBytes($tempPatch, $bytes)

try {
    py -3 $tempPatch $RepoRoot
}
finally {
    Remove-Item -LiteralPath $tempPatch -Force -ErrorAction SilentlyContinue
}

Write-Info "Patch completed."
Write-Info "Next checks:"
Write-Info "  cd backend"
Write-Info "  npm run build"
Write-Info "  cd ..\desktop-agent"
Write-Info "  py -3 -m py_compile src/main.py src/local_api.py src/todo/provider.py src/voice/phrases.py src/voice/controller.py"
Write-Info "  py -3 src/main.py"
